import React, { useState, useEffect } from 'react';
import { Stage, Client, GeneratedContent } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { Copy, Phone, Zap, Hash, Calendar, Edit2, Save, MessageSquare, Clock, CheckCircle, Timer, Trophy, CheckCircle2 } from 'lucide-react';
