interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [isEditing, setIsEditing] = useState(false);
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues({});
    setIsEditing(false);
    if (stage.template) {
        const generated = generateTemplateContent(stage, client, client.stageData || {});
        setEditableBody(generated.body);
    }
  }, [stage.id, client.id]);

  useEffect(() => {
    if (!isEditing && stage.template) {
        const generated = generateTemplateContent(stage, client, fieldValues);
        setEditableBody(generated.body);
    }
  }, [fieldValues, stage, client, isEditing]);

  const handleFieldChange = (variable: string, value: string) => {
    setFieldValues(prev => ({ ...prev, [variable]: value }));
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Copiado!");
  };

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const handleWhatsAppClick = () => {
    if (!client.phone) return;
    const cleanPhone = client.phone.replace(/\D/g, '');
    const encodedText = encodeURIComponent(editableBody);
    window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
    onUpdateClientStage(client.id, stage.id, fieldValues);
  };

  if (stage.id === '7') {
    const finishDate = client.stageHistory['7'];
    const totalDays = finishDate ? calculateDaysElapsed(client.createdAt, finishDate) : calculateDaysElapsed(client.createdAt);
    return (
      <div className="bg-white rounded-xl shadow-lg border border-gray-200 p-8 flex flex-col items-center justify-center text-center h-full">
          <div className="bg-green-100 p-6 rounded-full text-green-600 mb-6">
              <Trophy size={64} />
          </div>
          <h2 className="text-3xl font-black text-brand-900 mb-2 uppercase">Projeto Concluído!</h2>
          <p className="text-gray-500 mb-6">A jornada de {client.name} foi finalizada em {totalDays} dias.</p>
          <div className="grid grid-cols-2 gap-4 w-full max-w-md">
              <div className="bg-gray-50 p-4 rounded-xl border border-gray-100">
                  <p className="text-[10px] font-bold text-gray-400 uppercase">Início</p>
                  <p className="font-bold">{new Date(client.createdAt).toLocaleDateString('pt-BR')}</p>
              </div>
              <div className="bg-gray-50 p-4 rounded-xl border border-gray-100">
                  <p className="text-[10px] font-bold text-gray-400 uppercase">Fim</p>
                  <p className="font-bold">{finishDate ? new Date(finishDate).toLocaleDateString('pt-BR') : '-'}</p>
              </div>
          </div>
      </div>
    );
  }

  const requiredFields = stage.requiredFields || [];
  const areAllFieldsFilled = requiredFields.every(f => (fieldValues[f] || client.stageData?.[f])?.trim());

  return (
    <div className="bg-white rounded-xl shadow-lg border border-gray-200 flex flex-col h-full overflow-hidden">
      <div className="bg-brand-900 p-6 shrink-0 flex items-center justify-between text-white">
        <div>
          <h2 className="text-xl font-bold tracking-tight">Etapa {stage.stepNumber}: {stage.title}</h2>
          <p className="text-brand-300 text-xs">{stage.description}</p>
        </div>
        <div className="flex gap-2">
            <button onClick={() => setIsEditing(!isEditing)} className="p-2 hover:bg-white/10 rounded-lg transition">
                {isEditing ? <Save size={20} /> : <Edit2 size={20} />}
            </button>
        </div>
      </div>

      <div className="flex flex-col lg:flex-row flex-1 overflow-hidden">
        <div className="lg:w-80 p-6 overflow-y-auto border-r border-gray-100 bg-gray-50/30 flex flex-col gap-6">
           {requiredFields.length > 0 && (
               <div className="space-y-4">
                   <h3 className="text-[10px] font-black uppercase text-brand-800 tracking-widest">Dados da Etapa</h3>
                   {requiredFields.map(field => (
                       <div key={field}>
                           <label className="text-xs font-bold text-gray-500 mb-1 block capitalize">{field}</label>
                           <input 
                             type="text"
                             className="w-full p-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-gold-500/20 outline-none"
                             value={fieldValues[field] || client.stageData?.[field] || ''}
                             onChange={e => handleFieldChange(field, e.target.value)}
                             placeholder={`Informe ${field}...`}
                           />
                       </div>
                   ))}
               </div>
           )}
           <div className="mt-auto">
               <div className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm">
                   <p className="text-[10px] font-bold text-gray-400 uppercase mb-2">Cliente</p>
                   <p className="font-bold text-brand-900">{client.name}</p>
                   <p className="text-xs text-gray-500 font-mono mt-1">{client.phone}</p>
               </div>
           </div>
        </div>

        <div className="flex-1 p-6 flex flex-col gap-4">
            <div className="flex-1 bg-white border border-gray-200 rounded-xl overflow-hidden flex flex-col">
                <div className="bg-gray-50 px-4 py-2 border-b border-gray-100 flex justify-between items-center">
                    <span className="text-[10px] font-bold text-gray-400 uppercase">Mensagem WhatsApp</span>
                    <button onClick={() => copyToClipboard(editableBody)} className="text-brand-600 hover:text-brand-800"><Copy size={14} /></button>
                </div>
                {isEditing ? (
                    <textarea 
                      className="flex-1 p-4 text-sm font-sans resize-none outline-none"
                      value={editableBody}
                      onChange={e => setEditableBody(e.target.value)}
                    />
                ) : (
                    <div className="flex-1 p-4 text-sm whitespace-pre-wrap font-sans overflow-y-auto bg-gray-50/10">
                        {editableBody}
                    </div>
                )}
            </div>
            <button 
                onClick={handleWhatsAppClick}
                disabled={!areAllFieldsFilled}
                className={`w-full py-4 rounded-xl font-bold flex items-center justify-center gap-2 transition shadow-lg
                    ${areAllFieldsFilled ? 'bg-[#25D366] text-white hover:bg-[#1fb355]' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}
            >
                <Phone size={20} />
                Enviar Mensagem
            </button>
        </div>
      </div>
    </div>
  );
};

