import React, { useEffect, useRef } from 'react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { Stage } from '../types.ts';
import { Check } from 'lucide-react';

interface TimelineProps {
  currentStageId: string;
  onSelectStage: (stage: Stage) => void;
}

export const Timeline: React.FC<TimelineProps> = ({ currentStageId, onSelectStage }) => {
  const currentStageIndex = STAGES.findIndex(s => s.id === currentStageId);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      const activeElement = scrollRef.current.querySelector('[data-active="true"]');
      if (activeElement) {
        activeElement.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
      }
    }
  }, [currentStageId]);

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 w-full relative overflow-hidden shrink-0">
      <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-brand-900 to-gold-500"></div>

      <div 
        ref={scrollRef}
        className="flex overflow-x-auto gap-4 p-4 scrollbar-hide snap-x"
        style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
      >
        {STAGES.map((stage, index) => {
          const Icon = STEP_ICONS[stage.stepNumber] || STEP_ICONS['1'];
          const isActive = stage.id === currentStageId;
          const isCompleted = index < currentStageIndex;

          return (
            <div 
              key={stage.id}
              data-active={isActive}
              onClick={() => onSelectStage(stage)}
              className={`
                shrink-0 snap-center cursor-pointer transition-all duration-300
                flex flex-col items-center gap-2 p-3 rounded-xl min-w-[120px] border
                ${isActive 
                  ? 'bg-brand-50 border-brand-200 shadow-md ring-1 ring-brand-100' 
                  : isCompleted
                    ? 'bg-gray-50 border-gold-100 opacity-80'
                    : 'bg-transparent border-transparent opacity-40 hover:opacity-100'
                }
              `}
            >
              <div 
                className={`
                  flex items-center justify-center w-10 h-10 rounded-full border-2 transition-all
                  ${isActive 
                    ? 'border-brand-900 bg-brand-900 text-gold-400' 
                    : isCompleted 
                      ? 'border-gold-500 bg-gold-50 text-gold-600' 
                      : 'border-gray-200 bg-white text-gray-300'
                  }
                `}
              >
                {isCompleted ? <Check size={18} strokeWidth={3} /> : <Icon size={18} />}
              </div>

              <div className="flex flex-col items-center text-center">
                <span className="text-[8px] uppercase font-bold text-gray-400">Passo {stage.stepNumber}</span>
                <h3 className={`text-xs font-bold leading-tight ${isActive ? 'text-brand-900' : 'text-gray-500'}`}>
                  {stage.title}
                </h3>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

